async fn load_user(user_id: &str) -> String {
    format!("{}:user", user_id)
}

async fn load_profile(user_id: &str) -> String {
    format!("{}:profile", user_id)
}

fn merge(user: String, profile: String) -> String {
    format!("{}|{}", user, profile)
}

async fn app(user_id: &str) -> String {
    let (user, profile) = tokio::join!(load_user(user_id), load_profile(user_id),);
    let summary = merge(user, profile);
    summary
}
